// Accéder aux headers du webhook via $json.headers
const authHeader = $json.headers?.authorization || '';
const expectedToken = 'Bearer YOUR_TOKEN_HERE YOUR_WEBHOOK_TOKEN_HERE';

// Validation du token
if (!authHeader.startsWith('Bearer ')) {
  return [{ json: {
    status: 'error',
    code: 401,
    message: 'Missing or invalid Authorization header format. Expected: Bearer <token>'
  }}];
}

if (authHeader !== expectedToken) {
  return [{ json: {
    status: 'error',
    code: 401,
    message: 'Invalid authorization token'
  }}];
}

// Accéder au body du webhook via $json.body
const body = $json.body;
if (!body || !body.action) {
  return [{ json: {
    status: 'error',
    code: 400,
    message: 'Missing required field: action'
  }}];
}

// Validation des actions supportées
const validActions = ['audit', 'pause', 'resume', 'duplicate', 'export', 'cleanup'];
if (!validActions.includes(body.action)) {
  return [{ json: {
    status: 'error',
    code: 400,
    message: `Invalid action. Supported: ${validActions.join(', ')}`
  }}];
}

// Si tout est OK
return [{ json: {
  status: 'success',
  action: body.action,
  filters: body.filters || {},
  options: body.options || {},
  originalBody: body
}}];

// Node Code à ajouter avant Google Sheets
const auditData = $input.all()[0].json;
const processedRows = [];

// Traiter chaque type de rapport (Credentials, Nodes, Instance)
Object.entries(auditData).forEach(([reportKey, reportData]) => {
  if (reportData && reportData.sections) {
    reportData.sections.forEach(section => {
      processedRows.push({
        date: new Date().toISOString(),
        risk_type: reportData.risk,
        report_category: reportKey,
        section_title: section.title,
        description: section.description,
        recommendation: section.recommendation,
        issues_count: section.location ? section.location.length : 0,
        severity: getSeverity(reportData.risk, section.title),
        affected_workflows: section.location ? 
          [...new Set(section.location.map(item => item.workflowId).filter(Boolean))].join('; ') : 'N/A',
        issue_types: section.location ? 
          [...new Set(section.location.map(item => item.kind))].join('; ') : 'N/A'
      });
    });
  }
});

function getSeverity(riskType, sectionTitle) {
  if (riskType === 'nodes' && sectionTitle.includes('risky')) return 'Critical';
  if (riskType === 'instance' && sectionTitle.includes('webhook')) return 'High';
  if (riskType === 'credentials') return 'Medium';
  return 'Low';
}

return processedRows.map(row => ({ json: row }));

// Filtrer les workflows selon les critères spécifiés
const workflows = $input.all();
const filters = $('🔀 Action Router').item.json.filters || {};
const options = $('🔀 Action Router').item.json.options || {};

// Workflows protégés - sécurité renforcée
const protectedWorkflows = [
  'n8n-auto-maintenance', // Ne pas pauser le workflow de maintenance !
  'Security',
  'Backup'
];

let filteredWorkflows = workflows;

// Filtrer par nom si spécifié
if (filters.namePattern) {
  const regex = new RegExp(filters.namePattern, 'i');
  filteredWorkflows = filteredWorkflows.filter(wf => 
    regex.test(wf.json.name)
  );
}

// Filtrer par tags si spécifié
if (filters.tags) {
  const requiredTags = filters.tags.split(',').map(t => t.trim());
  filteredWorkflows = filteredWorkflows.filter(wf =>
    requiredTags.some(tag => 
      wf.json.tags?.some(wfTag => wfTag.name === tag)
    )
  );
}

// Exclure les workflows protégés (sécurité prioritaire)
filteredWorkflows = filteredWorkflows.filter(wf => {
  if (protectedWorkflows.includes(wf.json.name)) {
    console.warn(`⚠️ Workflow protégé exclu du filtrage: ${wf.json.name}`);
    return false;
  }
  return true;
});

// Exclure certains workflows critiques (logique existante)
const criticalWorkflows = options.excludeCritical ? 
  ['Security Audit', 'Backup System', 'Health Check'] : [];
filteredWorkflows = filteredWorkflows.filter(wf =>
  !criticalWorkflows.includes(wf.json.name)
);

return filteredWorkflows.map(wf => ({
  json: {
    id: wf.json.id,
    name: wf.json.name,
    active: wf.json.active,
    tags: wf.json.tags,
    action: 'pause'
  }
}));

const workflowData = $('📋 Get Workflow Details').item.json;

// ✅ Propriétés settings MINIMALES et généralement autorisées
const minimalSettings = {
  executionOrder: workflowData.settings?.executionOrder || "v1"
};

const updatePayload = {
  name: workflowData.name,
  nodes: workflowData.nodes,
  connections: workflowData.connections,
  settings: minimalSettings,  // ✅ Settings minimal mais requis
  active: false,
  staticData: workflowData.staticData || {}
};

return [{ 
  json: { 
    workflowJSON: JSON.stringify(updatePayload),
    workflowId: workflowData.id
  }
}];

// Filtrer les workflows pour duplication selon les critères optimisés avec IA
const workflows = $input.all();
const filters = $('🔀 Action Router').item.json.filters || {};
const options = $('🔀 Action Router').item.json.options || {};

// Workflows protégés - sécurité renforcée
const protectedWorkflows = [
  'n8n-auto-maintenance', // Ne pas dupliquer le workflow de maintenance !
  'Security',
  'Backup'
];

let filteredWorkflows = workflows;

// Filtrer par nom si spécifié
if (filters.namePattern) {
  const regex = new RegExp(filters.namePattern, 'i');
  filteredWorkflows = filteredWorkflows.filter(wf => 
    regex.test(wf.json.name)
  );
}

// Filtrer par tags si spécifié
if (filters.tags) {
  const requiredTags = filters.tags.split(',').map(t => t.trim());
  filteredWorkflows = filteredWorkflows.filter(wf =>
    requiredTags.some(tag => 
      wf.json.tags?.some(wfTag => wfTag.name === tag)
    )
  );
}

// Exclure les workflows protégés (sécurité prioritaire)
filteredWorkflows = filteredWorkflows.filter(wf => {
  if (protectedWorkflows.includes(wf.json.name)) {
    console.warn(`⚠️ Workflow protégé exclu de la duplication: ${wf.json.name}`);
    return false;
  }
  return true;
});

// Exclure certains workflows critiques
const criticalWorkflows = options.excludeCritical ? 
  ['Security Audit', 'Backup System', 'Health Check'] : [];
filteredWorkflows = filteredWorkflows.filter(wf =>
  !criticalWorkflows.includes(wf.json.name)
);

// 🚀 **LOGIQUE D'INTELLIGENCE ARTIFICIELLE POUR ÉVALUER L'INTÉRÊT**

// Fonction utilitaire pour calculer les jours depuis une date
function daysSince(dateString) {
  const date = new Date(dateString);
  const diffTime = Math.abs(new Date() - date);
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
}

// Système de scoring intelligent
filteredWorkflows = filteredWorkflows.filter(wf => {
  const json = wf.json;
  let score = 0;
  let reasons = [];

  // 📊 CRITÈRE 1: Statut d'activité (+2 points)
  if (json.active) {
    score += 2;
    reasons.push('actif');
  }

  // 🔧 CRITÈRE 2: Complexité du workflow (basée sur le nombre de nœuds)
  if (json.nodes && json.nodes.length > 20) {
    score += 3;
    reasons.push(`complexe (${json.nodes.length} nœuds)`);
  } else if (json.nodes && json.nodes.length > 10) {
    score += 1;
    reasons.push(`modérément complexe (${json.nodes.length} nœuds)`);
  }

  // 🏷️ CRITÈRE 3: Tags prioritaires (+3 points chacun)
  const priorityTags = ['important', 'critical', 'core', 'production', 'business'];
  if (json.tags) {
    for (const tag of json.tags) {
      if (priorityTags.includes(tag.name.toLowerCase())) {
        score += 3;
        reasons.push(`tag prioritaire: ${tag.name}`);
      }
    }
  }

  // ⏰ CRITÈRE 4: Récence des modifications
  if (json.updatedAt) {
    const days = daysSince(json.updatedAt);
    if (days < 7) {
      score += 3;
      reasons.push('récemment modifié (<7j)');
    } else if (days < 30) {
      score += 1;
      reasons.push('modifié récemment (<30j)');
    }
  }

  // 💼 CRITÈRE 5: Analyse sémantique du nom (patterns business-critiques)
  const businessPatterns = [
    /production/i, /business/i, /core/i, /main/i, /primary/i,
    /client/i, /customer/i, /order/i, /payment/i, /integration/i
  ];

  const isBusinessCritical = businessPatterns.some(pattern => 
    pattern.test(json.name)
  );

  if (isBusinessCritical) {
    score += 2;
    reasons.push('nom suggérant un workflow business-critique');
  }

  // 📈 CRITÈRE 6: Déclencheurs multiples (workflows complexes)
  if (json.triggerCount && json.triggerCount > 1) {
    score += 1;
    reasons.push(`${json.triggerCount} déclencheurs`);
  }

  // 🎯 DÉCISION FINALE : Seuil d'intérêt
  const isInteresting = score >= 3;

  // Logging pour debug
  if (isInteresting) {
    console.log(`✅ Workflow "${json.name}" sélectionné (score: ${score}) - Raisons: ${reasons.join(', ')}`);
  } else {
    console.log(`❌ Workflow "${json.name}" ignoré (score: ${score}) - Raisons: ${reasons.join(', ')}`);
  }

  return isInteresting;
});

return filteredWorkflows.map(wf => ({
  json: {
    id: wf.json.id,
    name: wf.json.name,
    active: wf.json.active,
    tags: wf.json.tags,
    action: 'duplicate'
  }
}));

// Préparer les données pour dupliquer TOUS les workflows
const allWorkflowsData = $('📋 Get Details for Duplicate').all();

console.log(`🔄 Traitement de ${allWorkflowsData.length} workflows pour duplication`);

const results = [];

allWorkflowsData.forEach((workflowItem, index) => {
  const workflowData = workflowItem.json;

  // Générer un nom unique pour chaque copie
  const originalName = workflowData.name;
  const timestamp = new Date().toISOString().split('T')[0]; // Format YYYY-MM-DD
  const duplicateName = `${originalName} - Backup ${timestamp}`;

  // Préparer le payload pour la création d'une copie
  const duplicatePayload = {
    name: duplicateName,
    nodes: workflowData.nodes,
    connections: workflowData.connections,
    settings: workflowData.settings || { executionOrder: "v1" },
    active: false, // Créer inactif par sécurité
    staticData: workflowData.staticData || {},
    tags: [
      ...(workflowData.tags || []),
      { 
        name: "backup",
        id: "backup-" + Date.now() + "-" + index
      },
      {
        name: "duplicate",
        id: "duplicate-" + Date.now() + "-" + index
      }
    ]
  };

  // Nettoyer les IDs des nœuds pour éviter les conflits
  if (duplicatePayload.nodes) {
    duplicatePayload.nodes = duplicatePayload.nodes.map(node => {
      const newNode = { ...node };
      // Générer un nouvel ID unique
      newNode.id = 'dup-' + Math.random().toString(36).substr(2, 9) + '-' + Date.now().toString(36) + '-' + index;
      return newNode;
    });
  }

  console.log(`🔄 Préparation duplication ${index + 1}/${allWorkflowsData.length}: "${originalName}" → "${duplicateName}"`);
  console.log(`📊 Nœuds à copier: ${duplicatePayload.nodes?.length || 0}`);

  results.push({ 
    json: { 
      workflowJSON: duplicatePayload,
      originalName: originalName,
      duplicateName: duplicateName,
      originalId: workflowData.id,
      batchIndex: index + 1,
      totalInBatch: allWorkflowsData.length
    }
  });
});

console.log(`✅ ${results.length} workflows préparés pour duplication`);
console.log(`🏷️ Tags ajoutés: backup, duplicate (avec index unique)`);

return results;

// Convertir l'objet workflow en JSON string pour l'API n8n
const workflowObj = $json.workflowJSON;

return [{
  json: {
    workflowJSON: JSON.stringify(workflowObj),
    originalName: $json.originalName,
    duplicateName: $json.duplicateName,
    originalId: $json.originalId,
    batchIndex: $json.batchIndex,
    totalInBatch: $json.totalInBatch
  }
}];

// Filtrage intelligent des workflows pour export
const workflows = $input.all();
const filters = $('🔀 Action Router').item.json.filters || {};
const options = $('🔀 Action Router').item.json.options || {};

// Workflows système (toujours inclus en export car critiques)
const systemWorkflows = ['n8n-auto-maintenance', 'Security', 'Backup'];

let filteredWorkflows = workflows;

// 🧠 INTELLIGENCE ARTIFICIELLE : Système de scoring pour workflows pertinents
function calculateExportValue(workflow) {
  const json = workflow.json;
  let score = 0;
  let reasons = [];

  // 🔥 CRITÈRE 1: Workflows système (toujours prioritaires)
  if (systemWorkflows.includes(json.name)) {
    score += 10;
    reasons.push('workflow système critique');
  }

  // 💼 CRITÈRE 2: Workflows business-critiques (analyse sémantique)
  const businessPatterns = [
    /production/i, /business/i, /core/i, /main/i, /primary/i,
    /client/i, /customer/i, /order/i, /payment/i, /integration/i,
    /api/i, /webhook/i, /sync/i, /import/i, /export/i, /notification/i
  ];

  const isBusinessCritical = businessPatterns.some(pattern => 
    pattern.test(json.name)
  );

  if (isBusinessCritical) {
    score += 5;
    reasons.push('nom suggérant un workflow business-critique');
  }

  // 🏷️ CRITÈRE 3: Tags prioritaires
  const priorityTags = ['important', 'critical', 'core', 'production', 'business', 'live'];
  if (json.tags) {
    for (const tag of json.tags) {
      if (priorityTags.includes(tag.name.toLowerCase())) {
        score += 4;
        reasons.push(`tag prioritaire: ${tag.name}`);
      }
    }
  }

  // ⚡ CRITÈRE 4: Workflows actifs (en utilisation)
  if (json.active) {
    score += 3;
    reasons.push('workflow actif');
  }

  // 🔧 CRITÈRE 5: Complexité technique (workflows sophistiqués)
  if (json.nodes && json.nodes.length > 15) {
    score += 3;
    reasons.push(`workflow complexe (${json.nodes.length} nœuds)`);
  } else if (json.nodes && json.nodes.length > 8) {
    score += 1;
    reasons.push(`workflow modérément complexe (${json.nodes.length} nœuds)`);
  }

  // ⏰ CRITÈRE 6: Activité récente (workflows maintenus)
  if (json.updatedAt) {
    const daysSince = Math.ceil((new Date() - new Date(json.updatedAt)) / (1000 * 60 * 60 * 24));
    if (daysSince < 30) {
      score += 2;
      reasons.push('récemment modifié (<30j)');
    } else if (daysSince < 90) {
      score += 1;
      reasons.push('modifié récemment (<90j)');
    }
  }

  // 📈 CRITÈRE 7: Workflows avec déclencheurs (automation active)
  if (json.triggerCount && json.triggerCount > 0) {
    score += 2;
    reasons.push(`${json.triggerCount} déclencheur(s)`);
  }

  // 🚫 CRITÈRES DE PÉNALITÉ (workflows à éviter)

  // Pénalité pour workflows de test
  const testPatterns = [/test/i, /demo/i, /example/i, /sample/i, /backup.*\d{4}/i];
  const isTestWorkflow = testPatterns.some(pattern => pattern.test(json.name));

  if (isTestWorkflow) {
    score -= 3;
    reasons.push('semble être un workflow de test/demo');
  }

  // Pénalité pour workflows inactifs depuis longtemps
  if (!json.active && json.updatedAt) {
    const daysSince = Math.ceil((new Date() - new Date(json.updatedAt)) / (1000 * 60 * 60 * 24));
    if (daysSince > 180) {
      score -= 2;
      reasons.push('inactif depuis >6 mois');
    }
  }

  return { score, reasons };
}

// Appliquer les filtres manuels d'abord
if (filters.namePattern) {
  const regex = new RegExp(filters.namePattern, 'i');
  filteredWorkflows = filteredWorkflows.filter(wf => 
    regex.test(wf.json.name)
  );
  console.log(`🔍 Filtrage par nom: ${filteredWorkflows.length} workflows correspondent à "${filters.namePattern}"`);
}

if (filters.tags) {
  const requiredTags = filters.tags.split(',').map(t => t.trim());
  filteredWorkflows = filteredWorkflows.filter(wf =>
    requiredTags.some(tag => 
      wf.json.tags?.some(wfTag => wfTag.name === tag)
    )
  );
  console.log(`🏷️ Filtrage par tags: ${filteredWorkflows.length} workflows avec tags requis`);
}

// 🧠 SÉLECTION INTELLIGENTE : Appliquer le scoring
const scoredWorkflows = filteredWorkflows.map(wf => {
  const analysis = calculateExportValue(wf);
  return {
    workflow: wf,
    score: analysis.score,
    reasons: analysis.reasons
  };
});

// Seuil intelligent : workflows avec score >= 5 OU workflows système
const selectedWorkflows = scoredWorkflows.filter(item => {
  const isSelected = item.score >= 5 || systemWorkflows.includes(item.workflow.json.name);

  if (isSelected) {
    console.log(`✅ "${item.workflow.json.name}" sélectionné (score: ${item.score}) - ${item.reasons.join(', ')}`);
  } else {
    console.log(`❌ "${item.workflow.json.name}" ignoré (score: ${item.score}) - ${item.reasons.join(', ')}`);
  }

  return isSelected;
});

// Si mode "force include" activé, inclure aussi les workflows avec score 3-4
if (options.includeModerateWorkflows) {
  const moderateWorkflows = scoredWorkflows.filter(item => 
    item.score >= 3 && item.score < 5 && !systemWorkflows.includes(item.workflow.json.name)
  );

  moderateWorkflows.forEach(item => {
    selectedWorkflows.push(item);
    console.log(`🟡 "${item.workflow.json.name}" inclus (mode étendu - score: ${item.score})`);
  });
}

// Statistiques finales
const stats = {
  total: workflows.length,
  afterFilters: filteredWorkflows.length,
  selected: selectedWorkflows.length,
  highValue: selectedWorkflows.filter(item => item.score >= 8).length,
  systemWorkflows: selectedWorkflows.filter(item => 
    systemWorkflows.includes(item.workflow.json.name)
  ).length
};

console.log(`📊 STATISTIQUES EXPORT:`);
console.log(`📦 Total workflows: ${stats.total}`);
console.log(`🔍 Après filtres manuels: ${stats.afterFilters}`);
console.log(`✅ Sélectionnés pour export: ${stats.selected}`);
console.log(`🔥 Haute valeur (score ≥8): ${stats.highValue}`);
console.log(`⚙️ Workflows système: ${stats.systemWorkflows}`);

return selectedWorkflows.map(item => ({
  json: {
    id: item.workflow.json.id,
    name: item.workflow.json.name,
    active: item.workflow.json.active,
    tags: item.workflow.json.tags,
    action: 'export',
    exportScore: item.score,
    exportReasons: item.reasons
  }
}));

// Préparer les données d'export avec métadonnées complètes - VERSION CORRIGÉE
const allWorkflows = $input.all();
const exportTimestamp = new Date().toISOString();
const exportDate = exportTimestamp.split('T')[0]; // Format YYYY-MM-DD

console.log(`📤 Préparation export de ${allWorkflows.length} workflows sélectionnés intelligemment`);

// Statistiques en temps réel
let stats = {
  totalWorkflows: allWorkflows.length,
  activeWorkflows: 0,
  inactiveWorkflows: 0,
  totalNodes: 0,
  workflowsWithCredentials: 0,
  workflowsWithTriggers: 0,
  systemWorkflows: 0,
  businessCritical: 0,
  highValueWorkflows: 0
};

// Traitement intelligent de chaque workflow
const processedWorkflows = allWorkflows.map((item, index) => {
  const workflow = item.json;
  const nodeCount = workflow.nodes?.length || 0;

  // Mise à jour des statistiques
  stats.totalNodes += nodeCount;
  if (workflow.active) stats.activeWorkflows++;
  else stats.inactiveWorkflows++;

  // Détection des credentials
  const hasCredentials = workflow.nodes?.some(node => 
    node.credentials && Object.keys(node.credentials).length > 0
  ) || false;
  if (hasCredentials) stats.workflowsWithCredentials++;

  // Détection des triggers
  const triggerCount = workflow.nodes?.filter(node => 
    node.type.includes('Trigger') || node.type.includes('trigger')
  ).length || 0;
  if (triggerCount > 0) stats.workflowsWithTriggers++;

  // Classification intelligente
  const systemWorkflows = ['n8n-auto-maintenance', 'Security', 'Backup'];
  const isSystemWorkflow = systemWorkflows.includes(workflow.name);
  if (isSystemWorkflow) stats.systemWorkflows++;

  const businessPatterns = [
    /production/i, /business/i, /core/i, /main/i, /primary/i,
    /client/i, /customer/i, /order/i, /payment/i, /integration/i,
    /api/i, /webhook/i, /sync/i, /import/i, /export/i, /notification/i
  ];
  const isBusinessCritical = businessPatterns.some(pattern => 
    pattern.test(workflow.name)
  );
  if (isBusinessCritical) stats.businessCritical++;

  // ✅ CORRECTION : Récupérer le score depuis les données du nœud actuel
  const exportScore = item.json.exportScore || 5; // Score par défaut si absent
  const exportReasons = item.json.exportReasons || ['sélectionné par filtrage intelligent'];
  if (exportScore >= 8) stats.highValueWorkflows++;

  // Structure d'export optimisée
  return {
    // Métadonnées principales
    id: workflow.id,
    name: workflow.name,
    active: workflow.active,
    versionId: workflow.versionId,

    // Timestamps
    createdAt: workflow.createdAt,
    updatedAt: workflow.updatedAt,
    exportedAt: exportTimestamp,

    // Structure workflow
    nodes: workflow.nodes,
    connections: workflow.connections,
    settings: workflow.settings || { executionOrder: "v1" },
    staticData: workflow.staticData || {},

    // Métadonnées organisationnelles
    tags: workflow.tags || [],

    // Analytics et insights pour l'import
    exportMetadata: {
      originallyActive: workflow.active,
      nodeCount: nodeCount,
      triggerCount: triggerCount,
      hasCredentials: hasCredentials,
      isSystemWorkflow: isSystemWorkflow,
      isBusinessCritical: isBusinessCritical,
      exportScore: exportScore,
      exportReasons: exportReasons,

      // Types de nœuds (pour statistiques)
      nodeTypes: workflow.nodes ? 
        [...new Set(workflow.nodes.map(node => node.type))].sort() : [],

      // Credentials utilisés (noms seulement, pas les valeurs)
      credentialTypes: hasCredentials ? 
        [...new Set(workflow.nodes.flatMap(node => 
          node.credentials ? Object.keys(node.credentials) : []
        ))].sort() : [],

      // Estimation de complexité
      complexityLevel: nodeCount < 5 ? 'Simple' : 
                      nodeCount < 15 ? 'Moderate' : 
                      nodeCount < 30 ? 'Complex' : 'Very Complex'
    }
  };
});

// Calculs statistiques finaux
stats.averageNodesPerWorkflow = Math.round(stats.totalNodes / stats.totalWorkflows);
stats.credentialCoverage = Math.round((stats.workflowsWithCredentials / stats.totalWorkflows) * 100);
stats.activationRate = Math.round((stats.activeWorkflows / stats.totalWorkflows) * 100);

// Structure d'export complète avec métadonnées riches
const exportData = {
  // En-tête d'export
  metadata: {
    exportDate: exportDate,
    exportTimestamp: exportTimestamp,
    exportedBy: 'n8n-auto-maintenance',
    exportVersion: '2.0',
    sourceInstance: 'n8n-production', // À adapter

    // Statistiques détaillées
    statistics: stats,

    // Configuration d'export
    exportConfig: {
      intelligentFiltering: true,
      includeMetadata: true,
      includeSettings: true,
      includeStaticData: true,
      credentialsHandling: 'references-only'
    }
  },

  // Données des workflows
  workflows: processedWorkflows
};

// Génération du nom de fichier intelligent
const filenamePrefix = stats.businessCritical > 0 ? 'n8n-business-workflows' : 'n8n-workflows';
const filename = `${filenamePrefix}-export-${exportDate}.json`;

