// Préparer la réponse binaire pour téléchargement - VERSION CORRIGÉE
const exportData = $json.exportData;
const filename = $json.filename;
const stats = $json.stats;

console.log(`📤 Préparation réponse binaire pour export: ${filename}`);
console.log(`📊 Workflows à télécharger: ${stats.totalWorkflows}`);

// ✅ CORRECTION : Créer le contenu JSON avec Buffer.from()
const jsonContent = JSON.stringify(exportData, null, 2);
const binaryData = Buffer.from(jsonContent, 'utf8');

console.log(`📄 Taille fichier: ${binaryData.length} bytes (${Math.round(binaryData.length/1024)} KB)`);

// ✅ CORRECTION : Structure exacte requise par n8n
return [{
  json: {
    filename: filename,
    fileSize: binaryData.length,
    stats: stats,
    downloadReady: true
  },
  binary: {
    exportData: {
      data: binaryData,
      mimeType: 'application/json',
      fileName: filename
    }
  }
}];
